css:
* {
  box-shadow: none !important;
  text-shadow: none !important;
  filter: none !important;
}

:not([class*="fa-"]):not(.fas):not(.far):not(.fal):not(.fab):not(.fa),
#send_textarea,
.menu_button_icon.fa-repeat,
.menu_button_icon.fa-bolt {
  font-family: system-ui;
}

.menu_button_icon.fa-repeat::before,
.menu_button_icon.fa-bolt::before {
  font-family: "Font Awesome 6 Free";
  font-weight: 900;
}

#top-settings-holder {
  background-color: var(--SmartThemeBorderColor);
}

.drawer-icon {
  transform: scale(0.8);
}

::-webkit-scrollbar {
  display: none;
}

#chat::-webkit-scrollbar {
  display: block;
  width: 3px;
}

#chat::-webkit-scrollbar-thumb {
  border: none;
  box-shadow: none;
  background-color: var(--SmartThemeUnderlineColor);
}

.drawer-content {
  border-radius: 0 0 12px 12px;
}

.avatar img:not(.mesAvatarWrapper .avatar img):not(#user_avatar_block img) {
  border: 2.5px solid var(--SmartThemeEmColor);
}

#chat {
  border: none;
}

.mes {
  flex-direction: column;
  margin-left: auto;
  margin-right: 5px;
  width: 88%;
  top: 80px;
  margin-bottom: 120px !important;
  border: none !important;
}

.mesAvatarWrapper .avatar {
  margin-top: -80px;
  margin-left: -45px;
}

.mesAvatarWrapper .avatar img {
  transform: scale(1.1);
  border: 2.5px solid rgba(74, 74, 74, 0.8);
}

.mesIDDisplay,
.mes_timer,
.tokenCounterDisplay {
  display: inline-block;    
  transform: scale(1.1);
  margin-right: 15px;
}

.mes[is_user="true"] .mesIDDisplay,
.mes[is_user="true"] .tokenCounterDisplay {
  margin: 0 -2px;
}

.mes.last_mes .mesIDDisplay,
.mes.last_mes .mes_timer,
.mes.last_mes .tokenCounterDisplay,
.mes.last_mes > *:not(.mes_block) {
  padding-bottom: 0;
}

.mes_text {
  width: 100%;
  padding: 0 10px 0 0;
  margin-bottom: 40px;
}

.mes pre code {
  background-color: var(--black30a);
  border-left: 3px solid var(--SmartThemeQuoteColor) !important;
  border: none;
  border-radius: 10px !important;
}

.mes_file_container {
  margin-top: -25px;
}

.swipe_left {
  margin-left: -12px;
  transform: scale(0.8);
}

.swipe_right {
  transform: scale(0.8);
}

#form_sheld {
  margin: 0px;
}

#send_form {
  border-radius: 0;
}

#nonQRFormItems .fa-solid {
  transform: scale(0.8);
}

.quickPersonaMenuImg {
  border: none !important;
}

.welcomePanel {
  border-radius: 0 0 12px 12px !important;
}

#left-nav-panel {
  padding-right: 0;
}

.completion_prompt_manager_header {
  color: var(--SmartThemeBodyColor) !important;
}

.standoutHeader,
#user-settings-block h4,
#user-settings-block .inline-drawer-header,
#rm_extensions_block .inline-drawer-header {
  position: relative;
  padding-left: 10px !important;
  background: none !important;
  border-radius: 0 !important;
  border: none !important;
}

.standoutHeader::before,
#user-settings-block h4::before,
#user-settings-block .inline-drawer-header::before,
#rm_extensions_block .inline-drawer-header::before {
  content: "";
  position: absolute;
  left: 3px;
  top: 5px;
  bottom: 4px;
  width: 3px;
  background-color: var(--SmartThemeQuoteColor);
}

.online_status_indicator {
  transform: scale(0.7);
}

.world_entry_form {
  border: none;
}

.fav_on {
  color: var(--SmartThemeQuoteColor) !important;
}

#user_avatar_block .avatar img {
  border: none !important;
}

#lock_persona_default.locked {
  border-color: #F8D300;
}

#persona_connections_list .avatar img {
  border: none !important;
}

#HotSwapWrapper {
  overflow-x: auto;
}

#HotSwapWrapper::-webkit-scrollbar {
  display: none;
}

.hotswap.avatars_inline {
  min-width: max-content;
}

.hotswap.avatars_inline > .avatar.inline_avatar {
  display: inline-block;
}

#HotSwapWrapper * {
  max-width: none;
}

.character_select.is_fav .avatar img,
.group_select.is_fav .avatar img,
.group_member.is_fav .avatar img {
  border: none !important;
}

.character_select.is_fav .avatar,
.group_select.is_fav .avatar,
.group_member.is_fav .avatar,
.avatar.is_fav {
  outline: 2px solid var(--SmartThemeQuoteColor);
}

.character_select.is_fav .ch_name,
.group_select.is_fav .ch_name,
.group_member.is_fav .ch_name {
  color: var(--SmartThemeQuoteColor);
}

.tag {
  border: none;
}

.tag_view_name {
  border: none;
  outline: none !important;
}

select {
  padding: 4px 6px !important;
}

input[type="checkbox"]:checked {
  background: var(--SmartThemeQuoteColor);
  border: none;
}

input[type="checkbox"]::before {
  box-shadow: inset 1em 1em color-mix(in srgb, var(--SmartThemeBodyColor) 95%, black);
}

input[type="range"] {
  background: transparent; 
}

input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 13px;
  height: 13px;
  transform: scaleY(2.5);
  background: var(--SmartThemeShadowColor);
}

input[type="range"]::-webkit-slider-runnable-track {
  background: var(--SmartThemeShadowColor);
  border-radius: 6px 6px 0 0;
  transform: scaleY(0.4);
}

.menu_button {
  background: none !important;
}

:not(#persona_connections_buttons) > .menu_button,
.menu_button:not([id^="lock_"]) {
  border: none !important;
}

.inline-drawer-icon {
  font-size: 14px;
}

.fa-unlock.right_menu_button,
.fa-lock.right_menu_button,
.fa-list-ul {
  font-size: 20px !important;
}

.toast {
  background-color: rgba(79, 79, 79, 0.6) !important;
  border-radius: 18px !important;
  font-size: 12px !important;
  padding: 25px !important;
  padding-left: 50px !important;
}
